import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';

function MarkAttendance({ user }) {
  const [attendanceData, setAttendanceData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [success, setSuccess] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const checkAttendance = async () => {
      try {
        const response = await api.get('/attendance/');
        console.log('Attendance data:', response.data);
        setAttendanceData(response.data);
      } catch (err) {
        setError('Failed to load attendance data');
        console.error('Error loading attendance:', err);
      } finally {
        setLoading(false);
      }
    };   
    checkAttendance();
  }, []);

  const handleMarkAttendance = async () => {
    setSubmitting(true);
    setError('');
    setSuccess(false);
    
    try {
      // Mark attendance
      const response = await api.post('/attendance/');
      console.log('Mark attendance response:', response.data);
      
      // Update with the response data which includes the timestamp
      setAttendanceData({
        ...attendanceData,
        already_marked: true,
        can_mark: false,
        marked_at: response.data.marked_at,
        mark_time: response.data.mark_time
      });
      
      setSuccess(true);
      
      // Optional: Redirect after showing success message
      setTimeout(() => {
        if (user.is_admin) {
          navigate('/admin');
        } else {
          navigate('/dashboard');
        }
      }, 2000);
      
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to mark attendance');
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    if (user.is_admin) {
      navigate('/admin');
    } else {
      navigate('/dashboard');
    }
  };

  const getStatusMessage = () => {
    if (attendanceData?.on_leave) {
      return "You are on Leave today";
    }
    if (attendanceData?.on_wfh) {
      return "You are on Work From Home today";
    }
    if (attendanceData?.already_marked) {
      return "You have already marked attendance today";
    }
    return null;
  };

  // Format the date
  const formattedDate = new Date().toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'long', 
    day: 'numeric' 
  });

  // Format time from ISO string (matches view_attendance_api format)
  const formatTimeFromISO = (isoString) => {
    if (!isoString) return '';
    try {
      const date = new Date(isoString);
      return date.toLocaleTimeString('en-IN', { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit',
        hour12: true,
        timeZone: 'Asia/Kolkata'
      });
    } catch (error) {
      console.error('Error formatting time:', error);
      return isoString;
    }
  };

  if (loading) {
    return (
      <div style={styles.container}>
        <div style={styles.card}>
          <div style={styles.loading}>Loading...</div>
        </div>
      </div>
    );
  }

  const statusMessage = getStatusMessage();

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Mark Attendance</h2>
        <p style={styles.date}>Date: {formattedDate}</p>
        
        {error && (
          <div style={styles.error}>
            {error}
          </div>
        )}
        
        {success && (
          <div style={styles.success}>
            ✅ Attendance marked successfully!
            {attendanceData?.mark_time && (
              <div style={styles.successTime}>
                at {attendanceData.mark_time} IST
              </div>
            )}
          </div>
        )}
        
        {/* Show marking time if attendance is already marked */}
        {attendanceData?.already_marked && (
          <div style={styles.timeInfo}>
            <p style={styles.timeText}>
              ✅ Attendance already marked
            </p>
            {attendanceData.mark_time && (
              <p style={styles.timeValue}>
                at <strong>{attendanceData.mark_time}</strong> IST
              </p>
            )}
            {attendanceData.marked_at && !attendanceData.mark_time && (
              <p style={styles.timeValue}>
                at <strong>{formatTimeFromISO(attendanceData.marked_at)}</strong> IST
              </p>
            )}
          </div>
        )}
        
        {attendanceData?.can_mark ? (
          <button 
            onClick={handleMarkAttendance} 
            disabled={submitting}
            style={submitting ? {...styles.markButton, ...styles.disabledButton} : styles.markButton}
          >
            {submitting ? 'Marking...' : 'Mark Present'}
          </button>
        ) : (
          <div style={styles.info}>
            <p style={styles.infoText}>{statusMessage}</p>
          </div>
        )}
        
        <button 
          onClick={handleBack} 
          style={styles.backButton}
        >
          Back to Dashboard
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    minHeight: '100vh',
    padding: '20px',
    backgroundColor: '#f5f5f5',
  },
  card: {
    background: 'white',
    padding: '40px',
    borderRadius: '16px',
    width: '400px',
    maxWidth: '100%',
    textAlign: 'center',
    boxShadow: '0 5px 15px rgba(0,0,0,0.2)',
    border: '2px solid var(--moss-green)',
  },
  title: {
    color: 'var(--moss-dark)',
    fontSize: '28px',
    marginTop: 0,
    marginBottom: '20px',
    fontWeight: 500,
  },
  date: {
    fontSize: '18px',
    color: 'var(--moss-green)',
    backgroundColor: 'var(--moss-pale)',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '25px',
    fontWeight: 500,
  },
  timeInfo: {
    marginBottom: '25px',
    padding: '15px',
    backgroundColor: '#d4edda',
    border: '2px solid #c3e6cb',
    borderRadius: '8px',
  },
  timeText: {
    color: '#155724',
    fontSize: '16px',
    margin: '5px 0',
    fontWeight: 500,
  },
  timeValue: {
    color: '#155724',
    fontSize: '18px',
    margin: '5px 0',
    fontWeight: 'bold',
  },
  markButton: {
    padding: '14px 25px',
    backgroundColor: 'var(--moss-green)',
    color: 'white',
    border: '1px solid var(--moss-dark)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'all 0.2s',
    width: '100%',
    fontWeight: 500,
  },
  disabledButton: {
    opacity: 0.6,
    cursor: 'not-allowed',
    backgroundColor: '#cccccc',
    borderColor: '#999999',
  },
  backButton: {
    padding: '12px 25px',
    backgroundColor: 'var(--moss-pale)',
    color: 'var(--moss-dark)',
    border: '1px solid var(--moss-green)',
    borderRadius: '8px',
    cursor: 'pointer',
    margin: '10px 5px',
    fontSize: '16px',
    fontFamily: 'Times New Roman, Times, serif',
    transition: 'background-color 0.2s',
    width: '100%',
    fontWeight: 500,
  },
  error: {
    color: '#721c24',
    backgroundColor: '#f8d7da',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '2px solid #f5c6cb',
  },
  success: {
    color: '#155724',
    backgroundColor: '#d4edda',
    padding: '12px',
    borderRadius: '8px',
    marginBottom: '20px',
    border: '2px solid #c3e6cb',
    fontWeight: 500,
  },
  successTime: {
    fontSize: '14px',
    marginTop: '5px',
    opacity: 0.9,
    color: '#155724',
  },
  info: {
    marginBottom: '20px',
  },
  infoText: {
    color: 'var(--moss-dark)',
    backgroundColor: 'var(--moss-pale)',
    padding: '15px',
    borderRadius: '8px',
    fontSize: '16px',
    border: '1px solid var(--moss-green)',
  },
  loading: {
    fontSize: '18px',
    color: 'var(--moss-dark)',
    padding: '20px',
  },
};

export default MarkAttendance;
